# To implement the Insertion Sort algorithm in Python, analyze its time complexity by
# counting the number of comparisons, and measure execution time for large input data.

import time
def insertion_sort(arr):
    comparisons = 0
    for i in range(1, len(arr)):
        key = arr[i]
        j = i - 1
        while j >= 0 and arr[j] > key:
            comparisons += 1
            arr[j + 1] = arr[j]
            j -= 1
        if j >= 0:
            comparisons += 1
        arr[j + 1] = key
    return comparisons

import random
arr = [random.randint(1, 1000) for _ in range(1000)]

start_time = time.time()
comparisons = insertion_sort(arr)
end_time = time.time()

print(f"Sorted array: {arr}")
print(f"Number of comparisons: {comparisons}")
print(f"Execution time: {end_time - start_time:.6f} seconds")

